// // This module compares two 4-bit binary numbers and outputs whether the first number is less than, greater than, or equal to the second number.
module binary_comparator(
    input wire [3:0] a,
    input wire [3:0] b,
    output wire gt,
    output wire lt,
    output wire eq
    );

assign gt = (a > b);
assign lt = (a < b);
assign eq = (a == b);

endmodule
